mapper.select:
SELECT id, name, sex, tel, photo, create_time
    FROM tb_customer
WHERE id = #{customerId}

mapper.insert:
INSERT INTO tb_customer (
    username,
    password,
    tel
    , email
    , photo
)
VALUES (
    #{username},
    #{password},
    #{tel}
    , #{email}
    , #{photo}
)

mapper.update:
update tb_customer set
        username = #{request.username},
        name = #{request.name},
        sex = #{request.sex},
        email = #{request.email}
where id = #{customerId}
